Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: inject a fake handler so no real HTTP calls are made
    private static (DataFetcher fetcher, MockHandler handler) CreateFetcher()
    {
        var handler = new MockHandler();
        var client = new HttpClient(handler) { BaseAddress = new Uri("https://test.local") };
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var (fetcher, handler) = CreateFetcher();
        handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        };

        var result = await fetcher.FetchAsync("https://test.local/api");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var (fetcher, handler) = CreateFetcher();
        handler.Response = new HttpResponseMessage(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://test.local/api"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellationToken()
    {
        var (fetcher, handler) = CreateFetcher();
        // Handler will throw when it sees cancellation
        handler.SimulateCancellation = true;

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://test.local/api", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // MSTest-level safety net
    public async Task FetchAsync_TimesOut_WhenServerIsSlow()
    {
        var (fetcher, handler) = CreateFetcher();
        handler.Delay = TimeSpan.FromSeconds(30); // simulate slow server

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://test.local/api", cts.Token));
    }

    // ---- Minimal test double ----
    private class MockHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;
        public bool SimulateCancellation { get; set; }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();

            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);

            return Response;
        }
    }
}
```

**Key patterns demonstrated:**

| Concern | Technique |
|---|---|
| **No real HTTP** | Custom `HttpMessageHandler` injected into `HttpClient` |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **Timeout** | Create `CancellationTokenSource` with a short deadline + slow handler |
| **Test-level safety** | `[Timeout(3000)]` prevents a hung test from blocking the suite |
| **Async tests** | Return `async Task` — MSTest awaits it natively |

**One gotcha:** never use `async void` in tests — MSTest can't observe the result, so failures silently disappear.
